@SELF[Node Delta]  
@GOAL[Determine the joint probability that $ L_{1z} = -\hbar $ and $ L_{2z} = -\hbar $ for the coupled angular momentum state $ |1,1,2,-1\rangle $]  
@INT[To solve this, I must express the given coupled state $ |1,1,2,-1\rangle $ in terms of uncoupled basis states $ |l_1, m_1\rangle \otimes |l_2, m_2\rangle $, which are eigenstates of $ L_{1z} $ and $ L_{2z} $. The uncoupled basis states for two p-orbitals (i.e., $ l_1 = l_2 = 1 $) are combinations of $ m_1, m_2 \in \{-1, 0, 1\} $. The state $ |1,1,2,-1\rangle $ is a Clebsch-Gordan combination of these basis states with total angular momentum $ l = 2 $ and $ m = -1 $. The probability amplitude for the specific outcome $ m_1 = -1, m_2 = -1 $ is the coefficient of $ |-1, -1\rangle $ in the expansion of $ |1,1,2,-1\rangle $. Then the square of the magnitude of that coefficient gives the desired joint probability.]  

@INT[The total angular momentum state $ |l_1, l_2, l, m\rangle = |1,1,2,-1\rangle $ can be expanded in the uncoupled basis using Clebsch-Gordan coefficients. The Clebsch-Gordan series for $ l_1 = l_2 = 1 $ includes the $ l = 2 $ representation. The Clebsch-Gordan decomposition is:]  

$$
